// Register service
builder.Services.AddScoped<IYourService, YourService>();
```

### Request/Response Models

**Location**: `S:\01_Repos\BeFirst_APIs\BeFirst_APIs\Models\`

**Request Model** (`Request\YourRequest.cs`):
```csharp
using System.ComponentModel.DataAnnotations;

namespace APIs_BeFirst.Models.Request
{
    public class YourRequest
    {
        [Required]
        public int RequiredField { get; set; }

        [StringLength(100)]
        public string? OptionalField { get; set; }

        // Match database entity field names and types
    }
}
```

**Response Model** (`Response\YourResponse.cs`):
```csharp
namespace APIs_BeFirst.Models.Response
{
    public class YourResponse
    {
        public bool Success { get; set; }
        public string Message { get; set; }
        public int? RecordsProcessed { get; set; }
        public DateTime ProcessedAt { get; set; }

        public YourResponse()
        {
            ProcessedAt = DateTime.Now;
        }
    }
}
```

### Controller Pattern

**Location**: `S:\01_Repos\BeFirst_APIs\BeFirst_APIs\Controllers\`

```csharp
using APIs_BeFirst.Models.Request;
using APIs_BeFirst.Models.Response;
using APIs_BeFirst.Models.DataMachines;  // For entity types
using APIs_BeFirst.Service.YourService;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;

namespace APIs_BeFirst.Controllers
{
    [ApiController]
    [Route("[controller]")]
    public class YourController : ControllerBase
    {
        private readonly IYourService _yourService;
        private readonly ILogger<YourController> _logger;

        public YourController(IYourService yourService, ILogger<YourController> logger)
        {
            _yourService = yourService;
            _logger = logger;
        }

        [Authorize]
        [HttpPost("SubmitData")]
        [ProducesResponseType(typeof(YourResponse), StatusCodes.Status200OK)]
        [ProducesResponseType(StatusCodes.Status400BadRequest)]
        [ProducesResponseType(StatusCodes.Status401Unauthorized)]
        public async Task<ActionResult<YourResponse>> SubmitData([FromBody] YourRequest request)
        {
            try
            {
                _logger.LogInformation($"Data submission received: ID={request.RequiredField}");

                if (!ModelState.IsValid)
                    return BadRequest(ModelState);

                var result = await _yourService.SubmitDataAsync(request);

                return result.Success ? Ok(result) : BadRequest(result);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error in SubmitData endpoint");
                return StatusCode(500, $"Internal server error: {ex.Message}");
            }
        }

        [HttpGet("Health")]
        public IActionResult Health()
        {
            return Ok(new { Status = "Healthy", Service = "Your Controller", Timestamp = DateTime.Now });
        }
    }
}
```

### Key Patterns to Follow

**✅ DO**:
- Inject `DbContext` in service constructor
- Use `AddAsync`, `AddRangeAsync` for inserts
- Use `SaveChangesAsync` to commit changes
- Use LINQ queries with `Where`, `FirstOrDefaultAsync`, `ToListAsync`
- Match request model fields to database entity properties
- Return entity types directly (no custom mapping classes)
- Add XML documentation comments to all endpoints
- Include Health endpoint in every controller

**❌ DON'T**:
- Use raw SQL queries (`SqlConnection`, `SqlCommand`, `ExecuteNonQuery`)
- Use `AddWithValue` for parameters
- Create custom DTO classes when entities exist
- Use synchronous methods (`Add`, `SaveChanges`)
- Forget service registration in `Program.cs`
- Skip validation attributes on request models

### Database Entity Models

**Location**: `S:\01_Repos\BeFirst_APIs\BeFirst_APIs\Models\DataMachines\` (or `DataBase\`)

**Entities are auto-generated from database** - Never modify manually:
- Entity classes: `YourTable.cs` (singular, PascalCase)
- DbSet properties: `YourTables` (plural, in DbContext)
- Table names: `Your_Table` (snake_case in database)

**Example**:
- Entity: `MachinesExtractorAoiDatum` (singular)
- DbSet: `MachinesExtractorAoiData` (plural)
- Table: `Machines_Extractor_AOI_Data`

### Reference Examples

**Complete implementations**:
- `S:\01_Repos\BeFirst_APIs\BeFirst_APIs\Service\AOI\AOIService.cs` - Full CRUD with batch operations
- `S:\01_Repos\BeFirst_APIs\BeFirst_APIs\Service\Units.cs\UnitsService.cs` - Multiple DbContext injection
- `S:\01_Repos\BeFirst_APIs\BeFirst_APIs\Service\Material\MaterialService.cs` - Standard CRUD patterns
- `S:\01_Repos\BeFirst_APIs\BeFirst_APIs\Controllers\AOIController.cs` - Full REST controller with auth

