## BeFirst APIs - Entity Framework Core Pattern

**CRITICAL**: BeFirst_APIs project uses Entity Framework Core for ALL database operations. NEVER use raw SQL queries (SqlConnection, SqlCommand).

### Standard Service Pattern

**Location**: `S:\01_Repos\BeFirst_APIs\BeFirst_APIs\Service\`

**Service Structure**:
```csharp
using APIs_BeFirst.Models.Request;
using APIs_BeFirst.Models.Response;
using APIs_BeFirst.Models.DataMachines;  // or DataBase
using Microsoft.EntityFrameworkCore;

namespace APIs_BeFirst.Service.YourService
{
    public interface IYourService
    {
        Task<YourResponse> SubmitDataAsync(YourRequest request);
        Task<YourBatchResponse> SubmitBatchAsync(List<YourRequest> requests);
        Task<YourEntity?> GetConfigAsync(int id);
    }

    public class YourService : IYourService
    {
        protected readonly ProdMachinesResultsContext _contextMachines;
        // Or: protected readonly ProdDwhContext _context;

        public YourService(ProdMachinesResultsContext contextMachines)
        {
            _contextMachines = contextMachines;
        }

        public async Task<YourResponse> SubmitDataAsync(YourRequest request)
        {
            var response = new YourResponse();
            try
            {
                // Map request to entity
                var entity = new YourEntity
                {
                    Field1 = request.Field1,
                    Field2 = request.Field2 ?? defaultValue,
                    Timestamp = DateTime.Now
                };

                // EF Core operations
                await _contextMachines.YourDbSet.AddAsync(entity);
                await _contextMachines.SaveChangesAsync();

                response.Success = true;
                response.Message = "Data submitted successfully";
            }
            catch (Exception ex)
            {
                response.Success = false;
                response.Message = $"Error: {ex.Message}";
            }
            return response;
        }

        public async Task<YourBatchResponse> SubmitBatchAsync(List<YourRequest> requests)
        {
            var entities = requests.Select(r => new YourEntity { /* map fields */ }).ToList();
            await _contextMachines.YourDbSet.AddRangeAsync(entities);
            await _contextMachines.SaveChangesAsync();
            // ... return response
        }

        public async Task<YourEntity?> GetConfigAsync(int id)
        {
            return await _contextMachines.YourDbSet
                .Where(x => x.Id == id && x.Active == true)
                .FirstOrDefaultAsync();
        }
    }
}
```

